import (
	"container/heap"
	"math"
)

type State struct {
	cost int64
	i    int
	j    int
	t    int
}

type priorityQueue []*State

func (pq priorityQueue) Len() int { return len(pq) }

func (pq priorityQueue) Less(i, j int) bool { return pq[i].cost < pq[j].cost }

func (pq priorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *priorityQueue) Push(x interface{}) {
	item := x.(*State)
	*pq = append(*pq, item)
}

func (pq *priorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])

	// Precompute teleportList
	teleportList := make([][][2]int, m)
	for i := 0; i < m; i++ {
		teleportList[i] = make([][2]int, n)
		for j := 0; j < n; j++ {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						teleportList[i][j] = append(teleportList[i][j], [2]int{x, y})
					}
				}
			}
		}
	}

	// Initialize distance array
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, int(k)+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}

	// Initialize priority queue
	h := &priorityQueue{}
	heap.Init(h)
	heap.Push(h, &State{cost: 0, i: 0, j: 0, t: 0})

	// Directions for regular moves: right and down
	directions := [][2]int{{0, 1}, {1, 0}}

	for h.Len() > 0 {
		state := heap.Pop(h).(*State)
		currentCost := state.cost
		i, j, t := state.i, state.j, state.t

		// Check if we reached the destination
		if i == m-1 && j == n-1 {
			return currentCost
		}

		// If current cost is higher than the recorded distance, skip
		if currentCost > dist[i][j][t] {
			continue
		}

		// Process regular moves
		for _, dir := range directions {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := currentCost + grid[ni][nj]
				if newCost < dist[ni][nj][t] {
					dist[ni][nj][t] = newCost
					heap.Push(h, &State{cost: newCost, i: ni, j: nj, t: t})
				}
			}
		}

		// Process teleportation
		for _, coord := range teleportList[i][j] {
			x, y := coord[0], coord[1]
			if t < int(k) {
				newT := t + 1
				if currentCost < dist[x][y][newT] {
					dist[x][y][newT] = currentCost
					heap.Push(h, &State{cost: currentCost, i: x, j: y, t: newT})
				}
			}
		}
	}

	// If we exit the loop without returning, it's impossible (but problem says there is a path)
	return -1
}
