import (
	"container/heap"
	"math"
)

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])

	// Preprocess teleport list
	teleportList := make([][][2]int, m)
	for i := 0; i < m; i++ {
		teleportList[i] = make([][2]int, n)
		for j := 0; j < n; j++ {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						teleportList[i][j] = append(teleportList[i][j], [2]int{x, y})
					}
				}
			}
		}
	}

	// Initialize distance array
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, int(k)+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}
	dist[0][0][int(k)] = 0

	// Define priority queue
	type State struct {
		cost int64
		i, j, k int
	}
	type PriorityQueue []*State

	// Define heap methods
	func (pq PriorityQueue) Len() int { return len(pq) }
	func (pq PriorityQueue) Less(i, j int) bool { return pq[i].cost < pq[j].cost }
	func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }
	func (pq *PriorityQueue) Push(x interface{}) {
		item := x.(*State)
		*pq = append(*pq, item)
	}
	func (pq *PriorityQueue) Pop() interface{} {
		old := *pq
		n := len(old)
		item := old[n-1]
		*pq = old[0 : n-1]
		return item
	}

	// Initialize priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &State{0, 0, 0, int(k)})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		cost := current.cost
		i, j, k_remaining := current.i, current.j, current.k

		// Check if destination is reached
		if i == m-1 && j == n-1 {
			return cost
		}

		// Skip if current cost is not the minimum
		if cost > dist[i][j][k_remaining] {
			continue
		}

		// Regular moves: right and down
		if j+1 < n {
			newCost := cost + grid[i][j+1]
			if newCost < dist[i][j+1][k_remaining] {
				dist[i][j+1][k_remaining] = newCost
				heap.Push(&pq, &State{newCost, i, j+1, k_remaining})
			}
		}
		if i+1 < m {
			newCost := cost + grid[i+1][j]
			if newCost < dist[i+1][j][k_remaining] {
				dist[i+1][j][k_remaining] = newCost
				heap.Push(&pq, &State{newCost, i+1, j, k_remaining})
			}
		}

		// Teleportation
		if k_remaining > 0 {
			for _, coord := range teleportList[i][j] {
				x, y := coord[0], coord[1]
				newK := k_remaining - 1
				if cost < dist[x][y][newK] {
					dist[x][y][newK] = cost
					heap.Push(&pq, &State{cost, x, y, newK})
				}
			}
		}
	}

	// If not found (should not happen)
	return dist[m-1][n-1][0]
}
